var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"저희 사람들이 출항 준비를 하는 동안, 여러분들은 편히 쉬고 계시면 돼요.","JPN":"こちらで出航準備をしている間、皆さんは少し休んでいてください。","ENG":"Why don't you rest while our staff gets the ship ready for departure?","TWN":"在我們做出航準備的這段時間，請各位先休息一下。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"전 마실 것들을 좀 가져오겠습니다.","JPN":"私はお飲み物を準備しましょう。","ENG":"I'll bring you some refreshments.","TWN":"我去拿點喝的過來。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_APSUMMER_NULL","text":{"KOREA":"아, 배려 감사합니다.","JPN":"あっ、お気遣いいただきありがとうございます。","ENG":"Oh, thank you.","TWN":"好的，非常感謝。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"어라? 카린 양은 언제 수영복으로 갈아입으셨어요?","JPN":"うん？　カリンさん、いつ水着に着替えたんですか？","ENG":"Err? Karin, when did you change into a swimsuit?","TWN":"咦？卡琳小姐什麼時候換上泳裝了？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"평소의 카린 양이라면 임무 도중에 노는 게 말이 되냐며 화낼 줄 알았는데.","JPN":"いつものカリンさんなら、任務中に遊ぶなんてお説教ものですよね？","ENG":"I thought the Karin I know would never agree to have fun while on a mission.","TWN":"如果是平時的卡琳小姐，一定會大發雷霆，說我在執行任務時偷懶的。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_APSUMMER_NULL","text":{"KOREA":"저, 저라고 항상 일 밖에 모르는 줄 알아요?","JPN":"わ、私だっていつも仕事のことばかり考えてるわけじゃありません。","ENG":"E-even I know how to have fun, you know.","TWN":"妳、妳以為我只知道工作嗎！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_APSUMMER_NULL","text":{"KOREA":"물론 시기적으로는 지금 임무를 수행 중이긴 하지만......","JPN":"もちろん、今は任務の最中ではありますが……","ENG":"It's true that we're currently on a mission,","TWN":"雖然現在確實是在執行任務的期間……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_APSUMMER_NULL","text":{"KOREA":"따지고 보면 저흰 조난을 당한 상황이고, 자력으로 돌아갈 방법도 없는데다가......","JPN":"よく考えてみれば私たちは遭難している状況で、自力で帰る方法もありませんし……","ENG":"but we've been stranded and are unable to go back on our own.","TWN":"但我們現在被困在這裡，也找不到回去的辦法……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_APSUMMER_NULL","text":{"KOREA":"수영을 하려면 당연히 수영복을 입어야 하는 거고......","JPN":"水泳をするなら当然水着に着替えるべきかと……","ENG":"Also, I have to wear a swimsuit to swim.","TWN":"而且游泳當然要穿泳裝……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_APSUMMER_NULL","text":{"KOREA":"그, 그리고 무엇보다 시영 씨도 항상 즐길 수 있을 때 즐기라고 나한테 그랬잖아요!","JPN":"そ、それに何よりシノンさんも遊べる時は遊べと、いつも言ってるではありませんか！","ENG":"M-moreover, you told me to have fun while I can!","TWN":"還、還有，時雨小姐不是常說該享受的時候就要盡情享受嗎？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"그럼요! 지당하신 말씀이죠!","JPN":"はい、おっしゃるとおりです！","ENG":"Absolutely! That's exactly what I told you.","TWN":"就是啊！妳說得對！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"카린 양이 점점 더 자기 합리화...... 아니 상황에 유연하게 대처하는 모습을 보니 참 기분이 좋네요, 하하하.","JPN":"カリンさんが自分の行動を合理化……いや、状況に合わせて柔軟に対処する姿が見れて嬉しいです、ハハハ。","ENG":"I'm glad to see you trying to justify—I mean, adapt to your situation. Hah hah.","TWN":"看到卡琳小姐越來越合理化自己的行為……不，遊刃有餘地應付危機的樣子，真讓人高興哪，哈哈哈。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_APSUMMER_NULL","text":{"KOREA":"크윽......","JPN":"くっ……","ENG":"Hmpf!","TWN":"唔……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"으으으음~ 개운해!","JPN":"う～ん、スッキリ！","ENG":"Mm, mm! I feel so refreshed!","TWN":"唔啊啊啊～好舒服！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"앗, 깨어났다.","JPN":"あっ、起きた。","ENG":"Ah, she's up!","TWN":"啊，醒了。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"응? 주위에 모르는 사람들이 잔뜩 있어.","JPN":"うん？　知らない人たちばっかり。","ENG":"Mm? Why am I surrounded by strangers?","TWN":"嗯？為什麼旁邊會有這麼多陌生人。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"다행히 성격은 원래대로 돌아온 것 같군요.","JPN":"幸い、性格は元に戻ったようですね。","ENG":"Thank God, she's back to being herself.","TWN":"幸好她恢復成原本的人格了。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"어째서 트윈즈라는 이름을 달고 있는지 이젠 알 거 같네요.","JPN":"なぜ名前にツインズがついてるか、わかるような気がします。","ENG":"Her surname, Twins, totally matches her personality.","TWN":"我好像知道她為什麼會叫“雙子”了。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_APSUMMER_NULL","text":{"KOREA":"뭐죠? 이 경보음은......?","JPN":"な、何ですか？　この警報は……？","ENG":"What's going on? Alarm is sounding.","TWN":"怎麼回事？這個警報是……？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"좀 잠잠해지나 했더니 뭔가 또 벌어지려나 보네요.","JPN":"やっと静かになったと思ったら、また何か起きたようですね。","ENG":"Apparently, not everything is settled.","TWN":"我還以為能夠安靜一會兒了，看樣子又有事要發生了呢。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"학교에 설치해둔 침식체 감지센서가 작동된 거야.","JPN":"学校に設置してある侵食体の感知センターが作動したんだよぉ。","ENG":"The school's C.O. sensors have been activated.","TWN":"是學校設置的侵蝕體感測器啟動了。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L28_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"뭔진 모르겠지만, 아무래도 이쪽으로 오려나 봐.","JPN":"どうしてかなぁ？　こっちに来てるみた～い。","ENG":"I don't know what they are, but they're coming this way.","TWN":"不知道是什麼，但好像正在接近這裡。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"OGRE1_NPC_NULL_NULL","text":{"KOREA":"(이대로 물러날 수는 없다!)","JPN":"(このまま引き下がるわけにはいかない！)","ENG":"(I can't leaves like this!)","TWN":"（不能就這樣退縮！）"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_36"},{"id":"L31_1","type":"dialog","speaker":"OGRE2_NPC_NULL_NULL","text":{"KOREA":"(저기 있다! 검은머리 여자!)","JPN":"(あそこにいる！　黒髪の女！)","ENG":"(There! The black-haired female!)","TWN":"（在那裡！黑髮女！）"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_32"},{"id":"L32_1","type":"dialog","speaker":"OGRE1_NPC_NULL_NULL","text":{"KOREA":"(데려간다! 무조건 데려간다!)","JPN":"(絶対に連れていく！　何があっても！)","ENG":"(I takes her! No matters what!)","TWN":"（帶走她！一定要帶走她！）"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_35"},{"id":"L33_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"설마 했더니 또 저것들이야?!","JPN":"まさかと思ったら、またあいつら！？","ENG":"Oh God, not again!","TWN":"該不會又是它們？！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"와아...... 저 녀석들, 이쯤되면 평범한 엑스트라가 아닌 것 같은데요?","JPN":"わぁ……あいつら、ただのエキストラにしちゃ出番多くないですか？","ENG":"Wow! They're way too persistent to be simple extras.","TWN":"哇……這些傢伙，能夠來到這裡，看來不是普通的配角喔？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"2막이 끝나가는데도 이런 상황이라면, 운명의 상대로선 유력후보라고 해도 되지 않으려나?","JPN":"第2幕も終盤だと言うのに、この調子だと彼らが運命の相手なのかもしれませんね？","ENG":"The second act is almost over, and yet they're back. Maybe they're strong candidates to be your soul mate.","TWN":"就算第二幕已經結束，但這樣應該可以登上命運之人的強力候補了！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"으아아악! 이건 말도 안돼! 싫어어!","JPN":"うわああ！　そんなの絶対にイヤー！","ENG":"Arrggh! No way! Noooo!","TWN":"啊啊啊！不可能！不要！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"어이! 우리가 돌아왔다!","JPN":"おい！　戻ってきたぞ！","ENG":"Hey, we're back!","TWN":"喂！我們回來了！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"아무리 생각해봐도 헬기까지 부숴먹었는데 이대로 물러서는 건 수지타산이 안 맞아!","JPN":"ヘリまで壊されて、このまま引き下がるわけにはいかないと思ってな！","ENG":"We can't leave empty-handed, no matter how hard. We have to make up for the chopper we lost.","TWN":"不管怎麼想，我們連直升機都墜毀了，就這樣回去實在虧大了！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"무슨 수를 써서라도 타깃을 데려간다!","JPN":"どんな手を使ってもターゲットを連れて帰る！","ENG":"We're taking her by fair means or foul!","TWN":"不管使出什麼手段，一定要帶走目標！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"엇, 그런데 저건...... 침식체 아닙니까? 어째서 이런 곳에?!","JPN":"あっ、でもあれは……侵食体じゃないですか？　どうしてこんなところに！","ENG":"Ah, but those... Aren't those C.O.s? What the hell are they doing here?","TWN":"呃，那是……侵蝕體？為什麼會在這裡？！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L44_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"에잇! 겁먹지 마! 이건 오히려 기회다!","JPN":"くっ！　恐れるな！　これはむしろチャンスだ！","ENG":"Gah! Don't be scared! This is better for us!","TWN":"喂！別慌張！這不如說是個好機會！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"놈들이 침식체들에게 정신이 팔린 틈을 타서 타겟을 손에 넣으면 되는 거야!","JPN":"やつらが侵食体たちに気を取られてる隙にターゲットを確保するぞ！","ENG":"We can grab the target and go while they're distracted by the C.O.s.","TWN":"趁她們對付侵蝕體的時候，我們可以一口氣拿下目標！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"이런. 순식간에 둘러싸였네요. 이를 어쩌면 좋죠?","JPN":"一瞬にして囲まれましたね。どうしましょう？","ENG":"Oopsie. We're surrounded. What do we do now?","TWN":"哎呀，瞬間被包圍了呢，怎麼辦？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_APSUMMER_NULL","text":{"KOREA":"나, 나한테 물어본다고 항상 뾰족한 수가 있는 줄 알아요?!","JPN":"わ、私に聞かれても困ります！","ENG":"I-I don't know. Stop asking me!","TWN":"妳、妳問我幹嘛，妳以為我每次都能想到好主意嗎？！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"하암~ 귀찮게 구는 녀석들이 많아서 잠도 못 자겠네.","JPN":"ふわぁ～、面倒くさいやつらが多くて眠れないよぉ。","ENG":"*Yawn* They're being so loud, I can't sleep.","TWN":"哈啊～這麼多煩人的傢伙，都沒辦法好好睡覺了。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"어쩔 수 없지, 이제 막 조립을 끝낸 시제기지만 실전 테스트도 할 겸 출격시켜 볼까?","JPN":"仕方ないなぁ。組み立てたばかりの試作機だけど、実戦テストも兼ねて出撃させてみようかなぁ？","ENG":"Oh well, I might as well use them to test this prototype that I just finished putting together.","TWN":"沒辦法了，雖然是才剛組裝完成的試用機，就當作是實戰測試順便出擊吧！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"야누스~","JPN":"ヤヌス～。","ENG":"Janus!","TWN":"雅努斯～"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"발진~!","JPN":"発進～！","ENG":"Launch!","TWN":"出擊～！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"으아아, 바닥이 흔들린다!","JPN":"うわぁ、地面が揺れてる！？","ENG":"Waaah, the ground is shaking!","TWN":"啊啊啊，地面在震動！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_DIVE"},{"id":"L11_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"대장! 수영장 바닥이 열리더니 갑자기 왠 전투기가 튀어나왔습니다!","JPN":"隊長！　プールの床から戦闘機が出てきました！","ENG":"Captain! The bottom of the pool opened up and a fighter came out!","TWN":"隊長！一架戰鬥機突然從泳池底下冒出來了！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"가, 갑자기 뭐야! 이 로봇만화 같은 전개는?","JPN":"な、何だ！　このロボット漫画みたいな展開は！？","ENG":"W-what the hell? This only happens in mecha anime!","TWN":"什、什麼！這種機器人漫畫的展開是？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"크윽, 하지만 이대로 물러설 순 없다! 공격해!","JPN":"くっ、しかしこのまま引き下がるわけにはいかない！　攻撃しろ！","ENG":"Gah, but we can't give up now! Onward!","TWN":"可惡，不能就這樣撤退！攻擊！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};